            {
                var arr = it.Split(':');
                emoji_group.Add(arr[0], arr[2]);
                if (!string.IsNullOrEmpty(arr[1]))
                {
                    if (emoji_skins.TryGetValue(arr[1], out var tmp)) tmp.Add(arr[0]);
                    else emoji_skins.Add(arr[1], new List<string>(6) { arr[0] });
                }
                var list = new List<string>(arr);
                list.RemoveAt(0);
                list.RemoveAt(0);
                list.RemoveAt(0);
                list.Insert(1, AntdUI.Pinyin.GetPinyin(list[0]).ToLower());
                list.Insert(2, AntdUI.Pinyin.GetInitials(list[0]).ToLower());
                emoji_keywords.Add(arr[0], list.ToArray());
            }
        }
